    {
        "path": "cronos-the-new-dawn-trainer/src/memory_scanner.py",
        "content": "\"\"\"\nMemory scanner module for Cronos: The New Dawn Trainer.\nProvides low-level memory scanning and pattern matching.\n\"\"\"\n\nimport ctypes\nimport ctypes.wintypes\nfrom typing import List, Optional, Tuple\n\n# Windows API constants\nPROCESS_VM_READ = 0x0010\nPROCESS_VM_WRITE = 0x0020\nPROCESS_VM_OPERATION = 0x0008\nPROCESS_QUERY_INFORMATION = 0x0400\n\n\nclass MemoryScanner:\n    \"\"\"Handles memory scanning and modification for a target process.\"\"\"\n\n    def __init__(self, process_name: str = \"CronosNewDawn.exe\"):\n        \"\"\"\n        Initialize the memory scanner.\n\n        Args:\n            process_name: The executable name of the target process.\n        \"\"\"\n        self.process_name = process_name\n        self.process_handle = None\n        self.pid = None\n\n    def find_process(self) -> bool:\n        \"\"\"\n        Locate the target process by name.\n\n        Returns:\n            True if process found, False otherwise.\n        \"\"\"\n        try:\n            import psutil\n            for proc in psutil.process_iter(['pid', 'name']):\n                if proc.info['name'] == self.process_name:\n                    self.pid = proc.info['pid']\n                    return True\n            return False\n        except ImportError:\n            print(\"psutil not installed. Please install it: pip install psutil\")\n            return False\n\n    def open_process(self) -> bool:\n        \"\"\"\n        Open a handle to the target process with necessary permissions.\n\n        Returns:\n            True if handle opened successfully.\n        \"\"\"\n        if not self.pid:\n            print(\"No process ID set. Call find_process() first.\")\n            return False\n\n        kernel32 = ctypes.windll.kernel32\n        self.process_handle = kernel32.OpenProcess(\n            PROCESS_VM_READ | PROCESS_VM_WRITE | PROCESS_VM_OPERATION | PROCESS_QUERY_INFORMATION,\n            False,\n            self.pid\n        )\n\n        if not self.process_handle:\n            print(f\"Failed to open process: {ctypes.GetLastError()}\")\n            return False\n        return True\n\n    def read_memory(self, address: int, size: int) -> Optional[bytes]:\n        \"\"\"\n        Read memory from the target process.\n\n        Args:\n            address: The memory address to read from.\n            size: Number of bytes to read.\n\n        Returns:\n            Bytes read or None on failure.\n        \"\"\"\n        if not self.process_handle:\n            print(\"Process handle not open.\")\n            return None\n\n        buffer = ctypes.create_string_buffer(size)\n        bytes_read = ctypes.c_size_t(0)\n\n        kernel32 = ctypes.windll.kernel32\n        success = kernel32.ReadProcessMemory(\n            self.process_handle,\n            ctypes.c_void_p(address),\n            buffer,\n            size,\n            ctypes.byref(bytes_read)\n        )\n\n        if not success:\n            print(f\"ReadProcessMemory failed at 0x{address:X}: {ctypes.GetLastError()}\")\n            return None\n\n        return buffer.raw[:bytes_read.value]\n\n    def write_memory(self, address: int, data: bytes) -> bool:\n        \"\"\"\n        Write data to the target process memory.\n\n        Args:\n            address: The memory address to write to.\n            data: Bytes to write.\n\n        Returns:\n            True if write succeeded.\n        \"\"\"\n        if not self.process_handle:\n            print(\"Process handle not open.\")\n            return False\n\n        bytes_written = ctypes.c_size_t(0)\n        kernel32 = ctypes.windll.kernel32\n\n        success = kernel32.WriteProcessMemory(\n            self.process_handle,\n            ctypes.c_void_p(address),\n            data,\n            len(data),\n            ctypes.byref(bytes_written)\n        )\n\n        if not success:\n            print(f\"WriteProcessMemory failed at 0x{address:X}: {ctypes.GetLastError()}\")\n            return False\n\n        return bytes_written.value == len(data)\n\n    def scan_value(self, value: int, region_start: int = 0x00400000,\n                   region_end: int = 0x7FFFFFFF) -> List[int]:\n        \"\"\"\n        Scan memory for a specific integer value.\n\n        Args:\n            value: The integer value to search for.\n            region_start: Start address of search region.\n            region_end: End address of search region.\n\n        Returns:\n            List of addresses where the value was found.\n        \"\"\"\n        found_addresses = []\n        chunk_size = 4096\n        value_bytes = ctypes.c_int32(value).value.to_bytes(4, 'little')\n\n        current_addr = region_start\n        while current_addr < region_end:\n            chunk = self.read_memory(current_addr, chunk_size)\n            if chunk:\n                pos = 0\n                while True:\n                    pos = chunk.find(value_bytes, pos)\n                    if pos == -1:\n                        break\n                    found_addresses.append(current_addr + pos)\n                    pos += 1\n            current_addr += chunk_size\n\n        return found_addresses\n\n    def close(self):\n        \"\"\"Close the process handle.\"\"\"\n        if self.process_handle:\n            ctypes.windll.kernel32.CloseHandle(self.process_handle)\n            self.process_handle = None\n            self.pid = None\n"
    },
